function Switchy(selector,option){this._container=document.querySelector(selector);if(!this._container){console.error(`${selector} not found`);return}this._tabs=Array.from(this._container.querySelectorAll(" li a"));this._panels=this._tabs.map(tab=>document.querySelector(tab.getAttribute("href"))).filter(Boolean);if(this._tabs.length!==this._panels.length){console.error("Tabs and panels must have the same length.");return}this._selector=selector;this._opt=Object.assign({classNameActive:"switchy--active",remember:true,onChange:null},option);this._originalHTML=this._container.innerHTML;this._searchParams=new URLSearchParams(location.search);this._init();this._handleTabClick()}Switchy.prototype._init=function(){const valueOfTab=this._searchParams.get(this._sanitizeQueryParams(this._selector));const tabActive=this._opt.remember&&valueOfTab?this._tabs.find(tab=>this._sanitizeQueryParams(tab.getAttribute("href"))===valueOfTab)||this._tabs[0]:this._tabs[0];this._currentTab=tabActive;this._activateTab(tabActive,false,false)};Switchy.prototype._handleTabClick=function(){this._tabs.forEach(tab=>{tab.onclick=e=>{e.preventDefault();this._checkActiveTab(tab)}})};Switchy.prototype._activateTab=function(elementTab,triggerOnchange=true,updateURL=this._opt.remember){this._tabs.forEach(tab=>{if(tab.closest("li").classList.contains(this._opt.classNameActive)){tab.closest("li").classList.remove(this._opt.classNameActive)}});elementTab.closest("li").classList.add(this._opt.classNameActive);this._panels.forEach(panel=>{panel.hidden=true});const panelActive=document.querySelector(elementTab.getAttribute("href"));panelActive.hidden=false;if(updateURL){this._searchParams=new URLSearchParams(location.search);this._searchParams.set(this._sanitizeQueryParams(this._selector),this._sanitizeQueryParams(elementTab.getAttribute("href")));history.replaceState(null,"",`?${this._searchParams}`)}if(typeof this._opt.onChange==="function"&&triggerOnchange){this._opt.onChange({tabActive:elementTab,panelActive:panelActive})}};Switchy.prototype.switch=function(input){let tabToActive=null;if(typeof input==="string"){tabToActive=this._tabs.find(tab=>tab.getAttribute("href")===input);if(!tabToActive){console.error(`${input} does not exits`);return}}else if(this._tabs.includes(input)){tabToActive=input}if(!tabToActive){console.error(`${input} does not exits`);return}this._checkActiveTab(tabToActive)};Switchy.prototype.destroy=function(){this._container.innerHTML=this._originalHTML;this._panels.forEach(panel=>panel.hidden=false);this._container=null;this._tabs=null;this._panels=null;this._currentTab=null;this._opt=null;this._searchParams=null;this._selector=null};Switchy.prototype._checkActiveTab=function(tab){if(this._currentTab!==tab){this._currentTab=tab;this._activateTab(tab)}};Switchy.prototype._sanitizeQueryParams=function(string){return string.replace(/[^a-zA-Z0-9]/g,"")};